INSERT INTO "backlog" VALUES(15,'Adaptive Bottom Navigation','feature','Dashboard fix + 3 konfigurierbare Favoriten + Mehr-Menü (Hamburger) für weitere Plugins. Skalierbar für Medikamente, Gewicht etc. Favoriten pro Nutzer konfigurierbar.',2,NULL,NULL,'done','2026-04-19 18:54:05','2026-04-20 05:13:59',NULL,NULL,NULL,NULL,NULL,NULL);
