INSERT INTO "backlog" VALUES(19,'Warnhinweise-System','feature','Backend-Logik + Dashboard-Banner: Dehydration (<5 nasse Windeln/24h), kein Stuhl (>48h), niedrige Trinkmenge. Portierung aus Home-Dashboard BabySummary.jsx.',1,NULL,NULL,'done','2026-04-20 03:04:55','2026-04-20 05:12:50',NULL,NULL,NULL,NULL,NULL,NULL);
