INSERT INTO "backlog" VALUES(21,'EntryListOverlay','feature','Detail-Ansicht + Bearbeitung aus 7-Tage Category-Buttons. Overlay/Modal mit Eintraegen eines Tages fuer eine Kategorie.',3,NULL,NULL,'cancelled','2026-04-20 03:04:55',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(22,'Temperatur +/- Buttons','feature','Plus/Minus-Buttons links/rechts neben dem Temperatur-Eingabefeld fuer Smartphone-Bedienung. Step 0.1.',2,NULL,NULL,'done','2026-04-20 11:36:07','2026-04-20 13:45:16',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(23,'Temperatur Untertemperatur-Warnung','feature','Rote Meldung auch bei Temperaturen unter 36.5 Grad (Hypothermie-Warnung).',3,NULL,NULL,'done','2026-04-20 11:36:07','2026-04-20 13:45:16',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(24,'Medikamenten-Stammdaten Backend','feature','Stammdatenverwaltung fuer Medikamente: Name, Wirkstoff, Masseinheit (Tablette, ml, Tropfen etc.). Dropdown-Auswahl statt Freitext bei Erfassung. Vordefinierte Masseinheiten.',2,NULL,NULL,'done','2026-04-20 11:36:07','2026-04-20 13:45:16',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(25,'Pflichtfelder mit Asterisk markieren','feature','Alle Pflichtfelder in Formularen mit * markieren. Input-Komponente erweitern.',3,NULL,NULL,'done','2026-04-20 11:36:07','2026-04-20 13:45:16',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(26,'Warnhinweise visuell staerker + nebeneinander','feature','AlertBanner staerker hervorheben, Flex-Box mit max-width fuer nebeneinander-Anzeige.',3,NULL,17,'done','2026-04-20 11:36:07','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(27,'Warnhinweise altersspezifisch','feature','Komplexes Schwellwert-System: Saeuglinge (0-1 Jahr) vs Kleinkinder (1-2 Jahre) benoetigen unterschiedliche Werte. Aus aktueller Entwicklung herausloesen.',3,NULL,17,'done','2026-04-20 11:36:07','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(28,'Dashboard Timer Start/Stop','feature','Laufenden Schlaf-Timer direkt vom Dashboard aus starten und stoppen koennen.',2,NULL,NULL,'done','2026-04-20 11:36:07','2026-04-20 13:45:16',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(29,'Tag-System fuer alle Eintraege','feature','Tags an alle Plugin-Eintraege anhaengen. Tag-Verwaltung im Backend (Name, Farbe, umbenennen, loeschen). Filter nach Tags in Listen. Klick auf Tag oeffnet gefilterte Suche. Zweck: Kinderarzt/Hebamme-Notizen.',2,NULL,4,'done','2026-04-20 11:36:07','2026-04-20 15:42:56',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(30,'Baby ToDo-Liste','feature','Schlanke ToDo-Liste: Titel, Details, Datum, Checkbox. Fuer Themen mit Kinderarzt/Hebamme.',3,NULL,4,'done','2026-04-20 11:36:07','2026-04-20 15:42:56',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(31,'ViewTabs visuell trennen','feature','Inaktive Tabs (Heute/7 Tage/14 Tage) visuell voneinander trennen statt grauer Balken.',4,NULL,NULL,'done','2026-04-20 11:36:07','2026-04-20 13:45:16',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(32,'Konsistenz-Feld entfernen','core','Konsistenz-Dropdown bei Windeln entfernen, Notizfeld stattdessen nutzen.',3,NULL,NULL,'done','2026-04-20 11:36:07','2026-04-20 13:45:16',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(33,'SSO-Integration (Authelia, OAuth2 Proxy)','feature','Forward-Auth-Modus mit Authelia vollständig integrieren. OAuth2 Proxy als Alternative unterstützen. AUTH_MODE=forward produktionsreif machen, inkl. Session-Handling und User-Mapping.',1,NULL,12,'done','2026-04-20 15:10:02',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(34,'Dashboard Quick-Add Button (FAB statt Button-Leiste)','feature','Die 6 Tracking-Buttons (Schlaf, Mahlzeiten, Windel, Temperatur, Gewicht, Medikament) im Dashboard durch einen einzelnen Plus-Button (FAB) ersetzen, der ein Auswahlmenü öffnet. Mobile: spart vertikalen Platz. Desktop: Plus-Icon oben rechts.',2,NULL,6,'done','2026-04-20 15:14:43',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(35,'Tagesverlauf: Eintraege klickbar (Detail + Edit)','feature','Tap/Klick auf Eintrag im DayTimeline-Diagramm oeffnet Detail-Ansicht mit Inline-Edit des jeweiligen Eintrags. [DEFERRED: User-Feedback von 3 Muettern — auf Smartphone zu klein/frickelig, wird nicht benoetigt]',2,NULL,NULL,'cancelled','2026-04-20 15:23:06',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(36,'Tagesverlauf: Konfigurierbare Plugin-Sichtbarkeit','feature','Zahnrad-Icon am Widget sowie Verwaltungs-Hub (/admin) steuern, welche Plugin-Typen im Tagesverlauf sichtbar sind (z.B. Medikamente, Ereignisse).',2,NULL,6,'done','2026-04-20 15:23:06',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(37,'Plugin: Emotionale Events (persoenliche Meilensteine)','feature','Frei erfassbare persoenliche Ereignisse ohne Norm-Schema: erstes Lachen, erste Weihnachten, erste Schritte, KiTa-erster-Tag etc. Strukturiert nach Lebensphase (0-6 Mon., 6-12 Mon., 1. Jahr, 2. Jahr) als optionale Kategorie. Freitext-Titel + Datum + optionales Foto/Notiz. Kein Pflicht-Schema, aber Vorlagen aus Bibliothek waehlbar. Quelle: 500 CONTEXTS/Home Lab Wiki/20 - Projekte/MyBabyTracker/BabyTracker-Events.md',3,NULL,10,'done','2026-04-20 15:23:06',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(38,'Plugin-Management: Plugins selektiv aktivieren/deaktivieren','feature','Basis-Plugins (Schlaf, Fuettern, Windeln) sind immer aktiv. Optionale Plugins (Gesundheit, Ereignisse etc.) koennen pro Kind im Verwaltungs-Hub aktiviert oder deaktiviert werden. Deaktivierte Plugins verschwinden aus Nav und Dashboard.',2,NULL,5,'done','2026-04-20 15:23:06','2026-04-21 08:05:46',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(39,'Bug: Temperatur-Widget - Grad-Celsius bricht auf separate Zeile um','bug','Im Temperatur-Widget steht der Wert (z.B. 35.6) und das Einheitenzeichen Grad Celsius auf zwei separaten Zeilen. Sollte inline dargestellt werden. Reproduzierbar auf mobilem Viewport.',2,NULL,4,'done','2026-04-20 15:23:44','2026-04-20 15:42:56',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(40,'Bug: VitaminD3-Widget - Text umbrechen (Vitamin D3 / Gegeben)','bug','Im VitaminD3-Status-Widget umbrechen "Vitamin D3" und "Gegeben" auf zwei Zeilen, da das Widget zu schmal ist. Layout-Fix: Schriftgroesse reduzieren, Text kuerzen oder Widget-Breite anpassen.',3,NULL,4,'done','2026-04-20 15:23:44','2026-04-20 15:42:56',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(41,'Dashboard: Seitentitel zeigt Datum + Uhrzeit + Kindname','feature','Auf der Dashboard-Seite ersetzt eine Kombination aus aktuellem Datum, Uhrzeit und Kindname den bisherigen Seitentitel. Datum/Uhrzeit werden minutengenau aktualisiert (Interval ~30s). Format-Vorschlag: "Montag, 20. April - 17:01 | Anna". Erleichtert gestressten Eltern schnelle Zeiterfassung ohne Blick auf die Systemstatusleiste.',3,NULL,4,'done','2026-04-20 15:26:51','2026-04-20 15:42:56',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(42,'PWA-Setup: Favicon, App-Name, Web-Manifest','core','Favicon (apple-touch-icon + favicon.ico) und Web App Manifest (manifest.json) einrichten. Browser-Tab-Titel auf "MyBaby" setzen. manifest.json mit name, short_name, icons (192px + 512px), display=standalone, background_color/theme_color (Catppuccin). Damit erscheint die App beim "Zum Homebildschirm hinzufügen" auf iPhone korrekt als eigenständige App mit eigenem Icon und ohne Browser-Chrome.',3,NULL,6,'done','2026-04-20 15:29:15',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(43,'Feeding: Stillseiten-Tracking (links/rechts)','feature','Im Fütterungs-Plugin die zuletzt gestillte Seite (links/rechts) speichern und im Dashboard prominent anzeigen. Die meistgestellte Frage von Hebammen in den ersten Wochen. Umsetzung: Feld "side" (left/right/both/bottle) in FeedingEntry, Dashboard-Toggle im BabySummary, Preset auf zuletzt verwendete Gegenseite.',1,NULL,6,'done','2026-04-20 15:36:10',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(44,'Warnhinweise: Fütterungsintervall-Alarm','feature','Warnung wenn seit mehr als 3 Stunden keine Mahlzeit erfasst wurde. Medizinisch kritisch bei Neugeborenen (Hypoglykämie-Risiko, Gewichtsverlust). Als AlertConfig-Regel analog zu bestehenden Warnhinweisen. Schwellwert konfigurierbar (Standard: 3h). Severity: critical.',1,NULL,6,'done','2026-04-20 15:36:10',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(45,'Plugin: Entwicklungs-Meilensteine (U-Untersuchungen + WHO/CDC)','feature','Strukturierte Meilensteine in 4 MECE-Bereichen: Motorik grob, Motorik fein, Sprache & Kommunikation, Soziales & Kognition. Angelehnt an CDC/WHO-Entwicklungstabellen + U1-U9. Eintraege mit Datum, optionaler Notiz, Bereich-Tag. Kein Freitext-Chaos, sondern vorgegebene Meilensteinliste zum Abhhaken. Quelle: 500 CONTEXTS/Home Lab Wiki/20 - Projekte/MyBabyTracker/BabyTracker-Events.md',2,NULL,NULL,'done','2026-04-20 15:36:10',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(46,'Kindprofil: Frühgeborenen-Modus','feature','Optionales Flag "fruehgeboren" im Kindprofil mit Eingabe des Geburtstermin-Solldatums (ET). Korrigiertes Alter wird dann durchgaengig verwendet: Warnhinweis-Schwellwerte, Meilenstein-Berechnung, U-Untersuchungs-Faelligkeit. Kuerzeres Fuetterungsintervall (2h statt 3h) als Standard bei aktiviertem Flag. Wichtig fuer Fruehgeborene bis korr. Alter 2 Jahre.',3,NULL,NULL,'done','2026-04-20 15:36:10',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(47,'i18n: Mehrsprachigkeit (de/en, erweiterbar)','feature','Zentrale Übersetzungs-Infrastruktur für Frontend und Backend. Sprachumschaltung pro Nutzerkonto oder als App-Setting. Startsprachen: Deutsch (Standard) und Englisch. Architektur soll weitere Sprachen ohne Code-Änderungen ermöglichen (JSON-Ressourcen). Plugin-Texte müssen ebenfalls übersetzbar sein (Plugin-eigene Locale-Dateien). Betrifft: UI-Labels, Fehlermeldungen, Warnhinweise, E-Mail-Benachrichtigungen (zukünftig).',3,NULL,14,'done','2026-04-20 15:37:33',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(48,'Security: API-Key-Authentifizierung (AI-First Layer)','core','Leichtgewichtiger API-Key-Mechanismus als erstes Security-Layer für programmatischen Zugriff (KI-Integrationen, externe Tools). FastAPI Dependency mit X-API-Key Header. Keys in DB gespeichert (hashed, Argon2), Verwaltung im Admin-Hub. Scopes: read / write / admin. Rate-Limiting per Key via slowapi. Ergänzt Authelia (Human-Auth) um Machine-to-Machine-Auth. Kein Ersatz für SSO — koexistiert mit v0.7.0 SSO-Sprint.',2,NULL,5,'done','2026-04-20 16:07:45','2026-04-21 08:05:46',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(49,'UI: Button-Text "Nachtragen" durch "Eintragen" ersetzen','core','"Eintragen" ist neutraler und suggeriert nicht, dass etwas vergessen wurde. Betrifft alle Create-Forms in allen Plugins.',3,NULL,6,'done','2026-04-20 18:45:07',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(51,'Plugin: Bauchschmerzen + Spucken (Gesundheit)','feature','Einfaches Erfassungs-Plugin fuer gastrointestinale Symptome. Zwei Teilbereiche: (1) Spucken: Intensitaet (wenig/mittel/stark). (2) Bauchschmerzen: Intensitaet (wenig/mittel/stark) + Dauer (kurz ~1h / mittel 1-2h / lang >2h). Ziel: Korrelationsanalyse mit Medikamenten, Ernaehrung, etc. Kann dem uebergeordneten Gesundheits-Plugin zugeordnet werden.',2,NULL,5,'done','2026-04-20 18:45:07','2026-04-21 08:05:46',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(52,'Dashboard: Erfassen-Actions hinter Add-Menue buendeln','feature','Auf dem Dashboard die Erfassen-Aktionen nicht einzeln auflisten, sondern hinter einem "+ Erfassen"-Button als Auswahl-Menue anbieten. Reduziert visuellen Clutter auf dem Dashboard.',2,NULL,6,'done','2026-04-20 18:45:07',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(53,'Quick Actions: 3 konfigurierbare Favoriten + Add-Menue','feature','In Verwaltung > Quick-Actions koennen Benutzer 3 Favoriten-Aktionen per Dropdown waehlen. Darstellung: Button-Group ueber volle Breite — 3 Quick-Action-Buttons (dunkles Grau, mit Icons) + 1 Add-Menue-Button (Peach/Signalfarbe). Einzelne Buttons, keine zusammenhaengende Leiste. Konfiguration als Einstellungsfeld mit je einem Dropdown pro Quick-Action.',2,NULL,6,'done','2026-04-20 18:45:07',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(54,'UI: Edit-Form visuell im Stamm-Element einbetten','bug','Edit-Form soll visuell im Stamm-Eintrag geoeffnet werden: nur 4 runde Ecken gesamt (nicht 8). Der helle Rahmen umrahmt Eintrag + Edit-Form als Einheit. Edit-Form bekommt leicht helleren Hintergrund als Unterscheidung. Macht visuell klarer, welcher Eintrag gerade bearbeitet wird. Referenz: 500 CONTEXTS/Home Lab Wiki/20 - Projekte/MyBabyTracker/Feedback-Edit-Lists.md',2,NULL,6,'done','2026-04-20 18:45:07',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(55,'Dashboard: VitD3-Kalender entfernen + Widget-Layout 2-spaltig','feature','VitaminD3-Kalenderansicht entfernen (User-Feedback: zu viel, wenig nuetzlich). Neues Layout: Linke Spalte: Temperatur + Gewicht untereinander. Rechte Spalte: VitD3-Widget + Medikamenten-Liste. Medikamenten-Liste auf max. 4 Eintraege begrenzen (danach scrollen). Kein White-Space — Medikamente fuellen verfuegbare Hoehe. Feedback von 3 Muettern.',2,NULL,6,'done','2026-04-20 18:45:07',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(56,'Bug: Mahlzeit-Widget zeigt "3x" statt "3"','bug','Im Dashboard Mahlzeit-Widget wird die Anzahl mit "x" suffix angezeigt (z.B. "3x"). Konsistent mit anderen Widgets soll nur die Zahl angezeigt werden (z.B. "3").',3,NULL,6,'done','2026-04-20 18:45:07',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(57,'Windeln-Widget: Kacheln fuer Gesamt/Nass/Beides','feature','Windeln-Widget verbessern: Zahlen fuer Gesamt, Nass und Beides in kleinen Containern/Kacheln darstellen. Stuhl und Trocken als kleine Zusatzzahlen (90% der Eintraege sind nass oder beides). Je nach mobilem Platz ggf. mehr Kacheln anzeigen. Mobile-Test entscheidet.',3,NULL,6,'done','2026-04-20 18:45:07',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(58,'Dashboard: Kacheln verlinken auf Heute-Ansicht','bug','Klickbare Dashboard-Kacheln (BabySummary-Grid, Widgets) sollen auf die Heute-Ansicht (/heute) verlinken, nicht auf die 7-Tages-Ansicht. Erwartungskonformes Verhalten: Der Nutzer will beim Klick auf eine Kachel sehen, was heute passiert ist — nicht eine Wochenübersicht.',2,NULL,6,'done','2026-04-20 18:58:37',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(59,'Plugin: Tummy Time Tracking','feature','Neues Plugin zum Tracken von Bauchlage-Einheiten. Felder: Datum, Startzeit, Endzeit (Dauer wird berechnet). Ziel: Sicherstellen, dass das Kind weder zu viel noch zu wenig Tummy Time bekommt. Einfache Listenansicht + Widget auf Dashboard.',3,NULL,5,'done','2026-04-20 19:28:36','2026-04-21 08:05:46',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(60,'ToDo-Plugin: Wiederkehrende Aufgaben','feature','Erweiterung des bestehenden ToDo-Plugins um wiederkehrende Aufgaben (daily). Aufgaben sind pro Kind (nicht pro Nutzer). Beispiele: Tummy Time morgens, Reizkarten-Uebungen nachmittags, Spaziergang machen. IMPLEMENTIERUNGSHINWEIS: Echter Cron/Backend-Ansatz ist komplex — Vorlagen-Konzept bevorzugen: Template-ToDo, das per Knopfdruck fuer den aktuellen Tag geklont wird. Deckt denselben Bedarf einfacher.',3,NULL,NULL,'done','2026-04-20 19:28:36',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(61,'Windeln-Widget: Balken-Visualisierung','feature','Farbige Balkendiagramme im Windeln-Widget (analog Baby Buddy): Verhaeltnis von gesamt/nass/schmutzig visuell als Balken statt nur Zahlen. Rein frontend-seitig. WICHTIG: Separater Commit + manueller Live-Test vor weiterer Implementierung — Nutzer moechte Feature zuerst in Produktion begutachten.',3,NULL,5,'done','2026-04-20 19:54:16','2026-04-21 08:05:46',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(62,'VitD3 Zurueck-Button durch Edit-Icon ersetzen','bug','Zurueck-Button im VitD3-Widget der BabySummary durch dezentes Pencil-Icon ersetzen',2,NULL,6,'done','2026-04-20 21:34:21','2026-04-20 21:34:21',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(63,'Medikamenten-Widget Masseinheiten-Alignment','bug','Masseinheiten in Medikamentenliste auf Desktop und Mobile einheitlich und rechtsbuendig darstellen',2,NULL,6,'done','2026-04-20 21:34:21','2026-04-20 21:34:21',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(64,'Tags-Icon in Desktop-Sidebar','feature','Tags-Navigation in Desktop-Sidebar hinzufuegen fuer schnellen Zugriff',2,NULL,6,'done','2026-04-20 21:34:21','2026-04-20 21:34:21',NULL,NULL,NULL,NULL,NULL,NULL);
