INSERT INTO "backlog" VALUES(66,'Nutzerverwaltung (lokale Alternative zu SSO)','feature','Lokale Nutzerverwaltung fuer Deployments ohne SSO/Authelia. Registrierung, Login, Passwort-Reset.',2,NULL,13,'done','2026-04-20 21:46:38',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(67,'Nutzereinstellungen (pro User)','feature','Persoenliche Einstellungen pro Nutzer: Sprachpraeferenz, Benachrichtigungen, UI-Praeferenzen. Voraussetzung: #66 oder SSO (#33).',3,NULL,13,'done','2026-04-20 21:46:38',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(68,'Entwicklungssprünge: Anzeige im Dashboard','feature','Berechnung der 10 Entwicklungsspruenge (nach Plooij/Oje-ich-wachse) ab ET des Kindes. Anzeige: aktuelle Phase (Sturm/Sonne), naechster Sprung, Wochen-Countdown. Datengrundlage: ET im Kindprofil. Keine externe API — Berechnung lokal. Wissenschaftlicher Vorbehalt als Info-Hinweis im UI. Quelle: 500 CONTEXTS/Home Lab Wiki/20 - Projekte/MyBabyTracker/BabyTracker-Spruenge.md. VORAUSSETZUNG: #46 Kindprofil-Erweiterung (ET-Feld) muss abgeschlossen sein.',2,NULL,11,'done','2026-04-20 21:52:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(69,'Entwicklungssprünge: Sturmphase-Alert','feature','Optionaler Alert-Banner wenn Baby aktuell in Sturmphase eines Sprungs. Konfigurierbar an/aus in Warnhinweis-Einstellungen. Schweregrad: info (nicht critical).',3,NULL,10,'done','2026-04-20 21:52:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(70,'Fix: Leap-Popup — Lavender-Link zu Spruenge-Tab','bug','Im Leap-Popup-Modal soll ein klickbarer Link (lavender-Farbe) direkt zum Spruenge-Tab navigieren. Sofort-Fix.',1,NULL,9,'done','2026-04-21 09:59:34',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
