INSERT INTO "backlog" VALUES(72,'Fix: Stilloptionen ausblenden wenn Stillmodus deaktiviert','bug','Wenn Stillmodus in Verwaltung deaktiviert ist, sollen Stillseiten-Optionen (links/rechts) im FeedingForm nicht angezeigt werden. Sofort-Fix. Backlog-Ref: #8.',1,NULL,9,'done','2026-04-21 09:59:34',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
