INSERT INTO "backlog" VALUES(87,'Alte Eintraege bei Neu-Erstellung ausblenden','feature','Beim Erstellen eines neuen Eintrags die Liste darunter ausblenden. Erst in 7-Tage-Ansicht sichtbar. Julia-Feedback #12.',4,NULL,NULL,'done','2026-04-21 10:01:47',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(88,'Gesundheit-Plugin Crash untersuchen','bug','App wird schwarz beim Tippen auf Gesundheit-Plugin. Runtime-Fehler, Build fehlerfrei. Browser-Console noetig. Julia-Feedback #13.',1,NULL,10,'done','2026-04-21 10:01:47',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(89,'Feature: Widget-Grid Reihenfolge konfigurierbar','improvement','Nutzer kann die Reihenfolge der Widgets im Widget-Grid ueber Up/Down-Buttons in /admin/plugins festlegen. Reihenfolge wird in localStorage persistiert. Implementierung: getDashboardWidgetOrder() + setDashboardWidgetOrder() in pluginConfig.ts, Dashboard.tsx Widget-Render per .map() auf Order-Array umbauen, /admin/plugins Seite um Up/Down-Buttons erweitern.',3,NULL,10,'done','2026-04-21 13:34:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(90,'Feature: Recurring Tasks Frontend (Vorlagen-Tab in TodoPage)','feature','Backend (TodoTemplate Model, CRUD, Clone-to-Today) ist fertig. Fehlt: Vorlagen-Tab in TodoPage — Liste aller Templates, Toggle aktiv/inaktiv, Clone-Button erstellt TodoEntry mit due_date=heute.',2,NULL,10,'done','2026-04-21 13:45:59',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(91,'Bug: test_alerts.py — feeding_interval Fix','bug','Test schlaegt fehl bei feeding_interval Alert-Regel. Ursache untersuchen und Fix implementieren.',2,NULL,10,'done','2026-04-21 13:45:59',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(92,'Chore: entry_summary Batch-Optimierung','core','entry_summary Endpunkt feuert N+1 Queries. Auf Batch-Abfragen umstellen fuer bessere Performance bei grossem Datenbestand.',3,NULL,10,'done','2026-04-21 13:45:59',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(93,'Auth: Normales Login (lokale Credentials, Argon2)','feature','Username/Passwort-Login ohne SSO. Argon2-Hash, Session-Cookie. Basis fuer alle anderen Auth-Optionen.',1,NULL,12,'done','2026-04-21 13:57:21',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(94,'Auth: SSO via Authelia (Forward-Auth)','feature','AUTH_MODE=authelia: Authelia Forward-Auth Header (Remote-User) wird akzeptiert. Nutzer wird aus Header-Wert angelegt/gemappt. Basis: bestehende Header-Stripping-Middleware (K1).',1,NULL,12,'done','2026-04-21 13:57:21',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(95,'Auth: 2FA (TOTP)','feature','TOTP-basierte Zwei-Faktor-Authentifizierung fuer lokalen Login. QR-Code-Einrichtung, Backup-Codes.',2,NULL,12,'done','2026-04-21 13:57:21',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(96,'Auth: Passkeys (WebAuthn)','feature','WebAuthn/FIDO2 Passkey-Registrierung und -Login. Alternativ zu Passwort. iOS Safari + Chrome unterstuetzt.',2,NULL,12,'done','2026-04-21 13:57:21',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(97,'Auth: Login deaktivierbar (AUTH_MODE=disabled)','feature','AUTH_MODE=disabled deaktiviert jede Auth-Pruefung. Sinnvoll wenn App hinter Authelia/Forward-Auth im Home Lab laeuft. Bereits als Env-Variable vorbereitet — UI-Konfiguration und Doku ergaenzen.',1,NULL,12,'done','2026-04-21 13:57:21',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(98,'Nutzerprofil: Zeitzone einstellen','feature','Pro-Nutzer-Zeitzone (z.B. Europe/Berlin). Zeitberechnungen (Schlafanalyse, Warnhinweise) respektieren Nutzer-Zeitzone statt Server-UTC. Gespeichert im User-Profil.',2,NULL,13,'done','2026-04-21 13:57:21',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(99,'i18n: Spracheinstellung im Nutzerprofil','feature','Sprache (de/en) pro Nutzer im Profil speicherbar. Vorbereitung fuer Sprint 14 i18n. Aktuell nur Deutsch.',3,NULL,14,'done','2026-04-21 13:57:21',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(100,'Feature: Tasks & Habits — Plugin-Umbenennung + Habits-Tab','feature','Plugin ToDo wird umbenannt in "Tasks & Habits" mit zwei Tabs: (1) Aufgaben: bestehende ToDo-Funktionalitaet (Einmaltasks + Vorlagen mit Clone-to-Today). (2) Habits: echte wiederkehrende Gewohnheiten — konfigurierbar als taeglich oder an bestimmten Wochentagen (Mo/Di/Mi...). Elternteile sehen jeden Tag ihre faelligen Habits automatisch. Beispiele: Baden (nur Di/Fr/So), Spaziergang (taeglich), Reizkarten (Mo/Mi/Fr). Backend: APScheduler oder einfacherer Cron-Ansatz, der taeglich Habit-Entries generiert. UI: Habit-Konfiguration mit Wochentag-Checkboxen. HINWEIS: Wenn eine ausfuehrliche Dokumentation existiert (docs/research/ oder Vault), diese vor Implementierung konsultieren.',3,NULL,17,'done','2026-04-22 02:43:58','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(101,'Chore: Baby Buddy Datenmigration','core','DB bereinigt, Import-Script um Temperatur erweitert, 729 Eintraege importiert, 21 VitD3 manuell. Anna umbenannt zu Anna Viktoria Riedel.',2,NULL,10,'done','2026-04-22 03:08:43',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(102,'Chore: Feature-Doku DB-Schema anlegen (features + feature_dependencies)','core','Zwei neue Tabellen in project.db: (1) features: id, name, category (plugin/auth/dashboard/infra), description, status, version_added, backlog_id, entry_points (JSON), key_files (JSON), notes. (2) feature_dependencies: id, feature_id, depends_on_id, dependency_type (requires/optional/extends), description. Alembic-Migration NICHT benoetigt (project.db ist Projekt-Meta-DB, kein App-Schema).',2,NULL,NULL,'refined','2026-04-22 13:44:33',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(103,'Chore: Feature-Abhaengigkeiten erfassen','core','Alle bekannten Abhaengigkeiten zwischen Features in feature_dependencies eintragen. Bekannte Beispiele: Dashboard-Widgets -> Plugin-Architektur (requires), Warnhinweise -> Alert-Service (requires), Milestones-Widget -> Milestones-Plugin (requires), Auth-Guard -> Auth-System (requires), Tag-Badges -> Tag-System (requires). Ziel: Vollstaendige Dependency-Map.',2,NULL,NULL,'refined','2026-04-22 13:44:34',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(104,'Chore: Unabhaengiger Audit-Agent — Feature-Doku Vollstaendigkeitspruefung','core','Ein separater Agent prueft: (1) Sind alle backlog-Items mit status=done in der features-Tabelle vertreten? (2) Haben alle Features mindestens einen entry_point? (3) Sind offensichtliche Abhaengigkeiten erfasst? Output: Pruefbericht als Markdown in docs/research/. Der Audit-Agent hat KEINEN Schreibzugriff auf die DB — nur Lesezugriff + Report.',2,NULL,NULL,'refined','2026-04-22 13:44:34',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(105,'Chore: Feature-Doku als Markdown exportieren (FEATURES.md + DEPENDENCIES.md)','core','Script oder Agent exportiert die features + feature_dependencies Tabellen: docs/FEATURES.md (vollstaendige Feature-Liste mit Entry Points) und docs/DEPENDENCIES.md (Abhaengigkeits-Graph als Mermaid-Diagram). Beide Dateien koennen bei Sprint-Start automatisch regeneriert werden.',3,NULL,NULL,'refined','2026-04-22 13:44:34',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(106,'Fix: Wonder-Weeks-Sprungdaten korrigieren (seed_data.py)','bug','Vergleich mit thewonderweeks.com und App "Oje, ich wachse!" (Stand 2026-04-22) zeigt Abweichungen bei Sprungzeitraeumen, insbesondere Sprung 1 und 2. Sprungtitel und Inhaltsbeschreibungen stimmen. Fix: seed_data.py mit korrekten Wochen-Daten aktualisieren + neue Alembic-Migration um bestehende leap_definitions-Eintraege zu aktualisieren. Vor Implementierung offizielle Quellen nochmals verifizieren.',2,NULL,14,'done','2026-04-22 13:45:35',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(107,'Feature: Update-Benachrichtigung beim App-Start (Changelog-Overlay)','feature','Nach einem App-Update zeigt die App eine dezente Benachrichtigung (wie bestehende AlertBanner oben): "Update auf Version x.y — Erfahre, was sich geaendert hat." Klick/Tap oeffnet ein Overlay mit Release Notes (Text + optional Screenshots). Implementierung: Aktuelle Version aus Backend-Config lesen, mit localStorage-Stand der zuletzt gesehenen Version vergleichen. Overlay-Content: strukturiertes JSON im Repo (changelog.json) oder Markdown. Dismiss-Button schliesst und speichert gesehene Version in localStorage. Zielgruppe: Entwickler kann Nutzer proaktiv ueber Aenderungen informieren.',3,NULL,17,'done','2026-04-22 13:45:35','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(109,'Chore: Alle Features erfassen + Entry Points dokumentieren','core','Alle 11 Plugins + Cross-cutting Features in features-Tabelle eintragen. Pro Feature: entry_points (wo im Code als erstes schauen), key_files (router, model, component, tests). Cross-cutting: Auth-System, Dashboard, Plugin-Architektur, Tag-System, Admin-Hub, API-Keys, Warnhinweise, Milestones, Leap-Berechnung. Quelle: CLAUDE.md Abschnitt "Aktueller Stand" + Codebase-Scan.',2,NULL,NULL,'refined','2026-04-22 13:45:35',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(110,'Feature: U-Untersuchungen Tracking (U1-U9)','feature','Strukturiertes Tracking der deutschen Pflicht-Vorsorgeuntersuchungen U1-U9. Fälligkeitsdatum wird automatisch aus dem Geburtsdatum berechnet (z.B. U3: 4.-5. LW, U4: 3.-4. LM). Pro Untersuchung: Status (ausstehend/wahrgenommen/verpasst), Wahrgenommen-Datum, Ergebnis/Auffälligkeiten (Freitext), Kinderarzt-Notizen. Visualisierung: Liste mit Ampelfarben (ausstehend=gelb, wahrgenommen=grün, verpasst=rot). Enge Elternteile fragen Hebammen ständig nach dem nächsten U-Termin. Quelle: docs/research/2026-04-20-hebammen-feature-research.md Feature 3. Implementierungshinweis: Kann als eigenes Plugin oder als spezielle Kategorie im Milestones-Plugin (source_type=medical) realisiert werden — Entscheidung beim Coding Lead.',2,NULL,16,'done','2026-04-22 14:04:44','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(111,'Feature: Schreien & Beruhigung Tracking','feature','Timer-basiertes Tracking von Schreiphasen (analog Sleep-Plugin): Start, Ende, Dauer. Felder: Ursache (Hunger/Erschöpft/Koliken/Dreierabend/Unbekannt), Beruhigungsmethode (Tragen/Stillen/Schnuller/Spaziergang/Unbekannt), Notiz. Visualisierung: Tagesverteilung der Schreiphasen zeigt Muster — regelmäßiger Dreierabend (18–22 Uhr), mahlzeitenkorrelierte Muster, Kolik-Verdacht. Therapeutischer Wert: Eltern erkennen "Es sind 2h täglich, nicht 8h". Kann als eigenes Plugin oder Erweiterung des Health-Plugins realisiert werden. Quelle: docs/research/2026-04-20-hebammen-feature-research.md Feature 5 (Prio 2, ursprünglich v0.5.0 vorgeschlagen).',2,NULL,16,'done','2026-04-22 14:04:55','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(112,'Feature: Muttergesundheit / Wochenbett-Notizen (Hebammen-Visit)','feature','Optionales Notizbuch für Muttergesundheit im Wochenbett: Wochenbettblutung (Verlauf), Nahtschmerzen, allgemeines Befinden, Edinburgh-Skala (EPDS) für PPD-Screening. Datenschutz-Hinweis: Daten sind per se sensitiv — optionaler Bereich, nur auf explizite Aktivierung sichtbar. Primäre Zielgruppe: Hebamme + Mutter gemeinsam beim Visit. Klinisch relevant: PPD betrifft ~10-15% der Mütter, frühe Erkennung entscheidend. Minimalversion: Freitext-Notizbuch "Für Hebammen-Visit" ohne strukturierte Felder — Privacy-first. Quelle: docs/research/2026-04-20-hebammen-feature-research.md.',3,'v0.9.0',NULL,'refined','2026-04-22 14:05:10',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(113,'Feature: Wachstumskurven mit WHO-Perzentilen + Frühgeborenen-Kalibrierung','feature','Gewicht, Länge und Kopfumfang gegen WHO-Wachstumskurven (0-2 Jahre) visualisieren. Perzentilen-Berechnung automatisch aus Geburtsdatum. Frühgeborenen-Korrektur: Geburtsdatum + Schwangerschaftswochen bei Geburt → korrigiertes Alter für Perzentilen-Einordnung (Frühgeborenen-Modus bereits im Child-Model: is_preterm + estimated_birth_date). Ohne Korrektur sehen Eltern eines 36+0-Frühgeborenen systematisch falsche Perzentilen und werden unnötig beunruhigt. WHO-Daten: öffentlich verfügbar (CSV/JSON), lokal im Repo speichern. Hinweis: #45 (Milestones-Plugin) hat WHO nur im Titel, keine Kurven implementiert. Quelle: docs/research/2026-04-20-hebammen-feature-research.md Feature 6 (Prio 2, ursprünglich v0.6.0 vorgeschlagen).',2,NULL,16,'done','2026-04-22 14:06:19','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(114,'Feature: Schlaf-Gesamttracking mit altersspezifischem Zielwert','feature','Tages-Gesamtschlaf (alle Naps + Nacht summiert) im Dashboard anzeigen, verglichen mit altersspezifischem Zielwert (NSF/AAP-Empfehlungen). Beispiel: Neugeborenes 0-3 Monate: 14–17h — Anzeige "Heute: 12h 30min / Ziel: 14–17h" mit Farbindikator. Zielwerte nach Altersgruppen: 0-3M: 14-17h, 4-11M: 12-15h, 1-2J: 11-14h. Implementierung: Summierung der sleep-Einträge des Tages bereits machbar, Zielwert aus Alterstabelle. Schlaftracking ist implementiert — nur Zielwert-Overlay und Summierung fehlen. Opt-in via /admin/alerts oder separater Toggle. Quelle: docs/research/2026-04-20-hebammen-feature-research.md Feature 8 (Prio 3).',3,NULL,NULL,'done','2026-04-22 14:06:33','2026-04-24 06:45:20',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(115,'Feature: Mehrlinge-Modus (Zwillinge / bis zu 3 Kinder)','feature','Mehrere Kindprofile parallel auf einem Dashboard mit schnellem Umschalten. Setup: Beim Anlegen des ersten Kindes abfragen ob Mehrlinge (Anzahl 1-3). Daraufhin richtet sich die App ein. Synchron-Ansicht für Zwillinge: "beide zuletzt gefüttert?" — Side-by-Side oder Tab-Ansicht der kritischen Metriken pro Kind. Kind-Profil-System ist angelegt (Child-Model existiert), aber Multi-Child-Dashboard fehlt vollständig. Scope: bis zu 3 Kinder. Zwillinge in Hebammen-Praxis überrepräsentiert durch Reproduktionsmedizin — zwei separate Apps nicht praktikabel für erschöpfte Eltern. HINWEIS: Hoher Implementierungsaufwand — betrifft Dashboard, Navigation, alle Plugins, Alert-System, Preferences (per Kind). Eigener Sprint empfohlen. Quelle: docs/research/2026-04-20-hebammen-feature-research.md Feature 9 (Prio 3, ursprünglich v0.6.0).',3,NULL,NULL,'refined','2026-04-22 14:07:37',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(116,'Fix: Windel-Typ "gemischt" umbenennen in "dreckig"','bug','Im Windel-Plugin wird der Typ "gemischt" (nass + dreckig) als Label an Nutzern angezeigt. Umbenennen in "dreckig". Betrifft: DiaperForm.tsx (Dropdown-Label), DiaperList.tsx (Anzeige), DiaperWidget (Dashboard), Tagesverlauf-Tooltip, ggf. Backend-Enum oder nur Frontend-Label. Prüfen ob der Backend-Enum-Wert selbst geändert werden muss (dann Alembic-Migration + Datenmigration nötig) oder nur das Display-Label.',3,NULL,15,'done','2026-04-22 14:08:28','2026-04-23 06:28:41',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(117,'Feature: Schlaf-Ort optional (Bett/Tragetuch/Kinderwagen) mit Toggle','feature','Optionales Feld "Schlafplatz" im Sleep-Plugin: Bett, Tragetuch, Kinderwagen, Sofa, Unbekannt (Icon-Auswahl). Deaktiviert per Default — aktivierbar in /admin/settings via Toggle (analog Stillmodus-Toggle). Klinische Relevanz: Kinder die nur in Bewegung einschlafen können, signalisieren ein Schlafproblem das Hebammen/Schlafberater erkennen müssen. Visualisierung: Icon neben Schlaf-Eintrag in der Liste, ggf. Auswertung "Häufigster Schlafplatz diese Woche". HINWEIS: Ort wurde zuvor nach User-Feedback entfernt (Julia) — Toggle-Ansatz macht es opt-in statt Standard, vermeidet Rückschritt. Backend: sleep_entries.location Feld (nullable VARCHAR), Alembic-Migration.',3,NULL,16,'done','2026-04-22 14:08:52','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(118,'Review: Security Audit — Vollständige Sicherheitsprüfung','core','Unabhängiger Security-Review durch Code-Reviewer-Agent. Prüfpunkte: (1) K1-K4 Checkliste aus Architecture Spec (Header-Stripping, CSRF, Input-Validation, SECRET_KEY). (2) Auth-System: JWT-Konfiguration, Token-Expiry, Passkey-Implementierung, TOTP-Backup-Codes. (3) API-Keys: Argon2-Hashing, Scope-Enforcement. (4) OWASP Top 10: SQLi, XSS, IDOR, Mass Assignment. (5) Dependency-Audit: pip-audit + npm audit. (6) Secrets im Code/Git-History. Output: Security-Report als Markdown in docs/research/security-audit-YYYY-MM-DD.md. Kritische Findings blockieren Go Live.',1,NULL,NULL,'refined','2026-04-22 14:13:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(119,'Review: Code Quality Audit — Einfachheit, Wartbarkeit, Konsistenz','core','Unabhängiger Code-Quality-Review durch Code-Reviewer-Agent. Prüfpunkte: (1) Toter Code / ungenutzte Imports / doppelte Logik. (2) Konsistenz: Plugin-Struktur eingehalten? API-Konventionen? Schema-Patterns? (3) Komplexität: Gibt es Stellen die unnötig komplex sind — einfachere Lösung möglich? (4) Frontend: React Anti-Patterns, fehlende Keys, inkonsistente Komponenten-Struktur. (5) Test-Coverage-Gaps: Welche Pfade sind nicht getestet? (6) CLAUDE.md Konventionen eingehalten (UTCDatetime, Plugin-Struktur, Commit-Format). Output: Quality-Report als Markdown in docs/research/quality-audit-YYYY-MM-DD.md.',2,NULL,NULL,'refined','2026-04-22 14:13:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(120,'Review: Dependency-Health-Check (pip-audit + npm audit)','core','Alle Python- und Node-Abhängigkeiten auf bekannte CVEs prüfen. pip-audit auf requirements.txt, npm audit auf package.json. Veraltete Pakete mit Breaking-Change-Risiko identifizieren. Output: Liste der Findings mit Severity (Critical/High/Medium/Low). Critical + High müssen vor Go Live gefixt sein.',2,NULL,NULL,'refined','2026-04-22 14:13:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(121,'Feature: SmartHome-Anbindung (Home Assistant Phase 1, Alexa Phase 2)','feature','Sprachsteuerung und Automatisierung via Home Assistant (lokal, kein Cloud-Zwang). Phase 1 — Home Assistant: REST-Sensor oder Custom Integration liest MyBaby-Daten (letzte Mahlzeit, Schlafstatus, Windeln heute). Automatisierungen: "Wenn Anna seit 3h nicht gegessen → Benachrichtigung via HA". Quick-Log via HA-Dashboard-Button → MyBaby API (API-Key-Auth Scope=write bereits implementiert). Technisch: MyBaby REST-API ist bereits öffentlich per baby.familie-riedel.org erreichbar — HA kann direkt per HTTP-Request-Integration ansprechen. Phase 2 — Alexa: Custom Skill (Alexa Skills Kit) oder Alexa Routinen via HTTP-Request. Phase 3: Google Home, Siri Shortcuts. HINWEIS: HA läuft vermutlich bereits auf der NAS (Portainer) — Integration ist damit rein API-seitig, kein neues Deployment nötig.',3,NULL,NULL,'cancelled','2026-04-22 14:15:39',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(122,'Test: Wonder-Weeks-Sprungdaten pruefen (#106)','core','Meilensteine > Spruenge-Tab oeffnen. Alle 10 Spruenge pruefen: Sturmphase-Zeitraeume muessen mit offiziellen Wonder-Weeks-Daten uebereinstimmen. Besonders Sprung 1 (storm 4.5-5.5w) und Sprung 2 (storm 7.5-9.5w) verifizieren — waren vorher falsch. Leap-Status fuer Anna pruefen (korrekter aktiver Sprung?).',2,'v0.9.0',NULL,'refined','2026-04-22 14:44:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(123,'Test: i18n Deutsch — alle Seiten pruefen (#47)','core','Mit Sprache=Deutsch alle Seiten durchklicken: Dashboard (Tiles, Widgets, Timeline), Schlaf/Mahlzeiten/Windeln (Forms + Listen), Temperatur/Gewicht/Medikamente, Gesundheit, Bauchlage, Meilensteine (3 Tabs), ToDo (Aufgaben + Vorlagen), Verwaltung (alle Kacheln), Profil. Pruefen: Keine englischen Reste, keine fehlenden Keys (werden als Key-String angezeigt z.B. ''feeding.label_food_type''), Labels korrekt.',2,'v0.6.2',NULL,'refined','2026-04-22 14:44:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(124,'Test: i18n Englisch — alle Seiten pruefen (#47)','core','Sprache auf English umstellen (Profil oder localStorage). Dann alle Seiten durchklicken wie bei #123. Pruefen: Alle Strings auf Englisch, keine deutschen Reste, keine fehlenden Keys, Pluralformen korrekt (1 entry vs. 2 entries). Besonders: Option-Dropdowns (Sleep Type, Diaper Type, Feeding Type), Dashboard-Tiles, Warnhinweise, Admin-Seiten.',2,'v0.6.2',NULL,'refined','2026-04-22 14:44:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(125,'Test: Spracheinstellung im Profil (#99)','core','Profil-Seite oeffnen. Sprachauswahl-Dropdown sichtbar (Deutsch/English)? Sprache auf English umstellen — sofortige UI-Umschaltung ohne Reload? Seite neu laden — Sprache bleibt English (localStorage + Server-Sync)? Zurueck auf Deutsch — funktioniert? Bei AUTH_MODE=disabled: Sprache per localStorage umstellbar (Browser-Konsole: localStorage.setItem(''mybaby_language'', ''en''); location.reload())?',1,'v0.6.2',NULL,'refined','2026-04-22 14:44:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(126,'Test: i18n Sprachwechsel-Reaktivitaet (#47)','core','Waehrend der App-Nutzung Sprache wechseln (Profil). Pruefen: Option-Arrays in Dropdowns aktualisieren sich sofort (z.B. Schlaftyp: Nickerchen→Nap). Dashboard-Widgets reagieren. Navigation/BottomNav/MobileMenu Labels aendern sich. Kein Page-Reload noetig. Keine Artefakte (gemischte Sprachen).',3,'v0.6.2',NULL,'refined','2026-04-22 14:44:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(127,'UX: Sleep-Timer-Overlay zur Zeitanpassung','feature','Als Elternteil möchte ich durch Tippen auf die Kachel eines laufenden Sleep Timers ein Overlay öffnen, um die tatsächliche Startzeit nachträglich anpassen zu können, ohne den Timer abbrechen zu müssen.',3,NULL,15,'done','2026-04-22 21:00:53',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(128,'UX: Inline-Editing für Tasks (ohne Duplikation)','feature','Als Nutzer möchte ich, dass das Bearbeiten einer bestehenden Aufgabe als echtes Inline-Edit funktioniert und der Detailtext nicht doppelt angezeigt wird.',3,NULL,15,'done','2026-04-22 21:00:53',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(129,'UX: Aufgabenkachel — Detailstext zusammenklappbar','feature','Als mobiler Nutzer möchte ich, dass der Detailsbereich einer Aufgabenkachel standardmäßig auf ein bis zwei Zeilen gekürzt wird, mit Option zum Ausklappen.',4,NULL,15,'done','2026-04-22 21:00:53',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(130,'Feature: Geteiltes Notiz-Modul für Eltern','feature','Modulares Notiz-System mit Markdown-Input und visueller Oberfläche. Notizen können Meilensteinen, Schlafeinträgen oder anderen Ereignissen zugeordnet werden. Unterstützt Fotos, Checklisten und gemeinsame Bearbeitung durch beide Elternteile.',3,NULL,16,'done','2026-04-22 21:00:53','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(131,'Feature: Markdown Editor im Aufgaben-Detailbereich','feature','Als Nutzer möchte ich den Markdown Editor im Detailbereich von Aufgaben verwenden, damit ich Aufgaben mit Checklisten, Codeblöcken und formatiertem Text strukturieren kann.',4,NULL,17,'done','2026-04-22 21:00:53','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(132,'Bug: Fälligkeitsdatum/-uhrzeit aus Task nicht löschbar','bug','Wenn ein Task ein Fälligkeitsdatum oder eine Uhrzeit gesetzt hat, kann der Nutzer diese nur verändern, nicht löschen. Lösch-Button (X) neben Datum/Uhrzeit-Feld fehlt.',2,NULL,15,'done','2026-04-22 21:00:53',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(133,'UX: Medikamenten-Widget kompakt gestalten','feature','Das Medikamenten-Widget soll auf eine kompakte Größe reduziert werden und nur das zuletzt gegebene Medikament mit Zeitstempel anzeigen. Opt-In zur vollständigen Liste.',4,NULL,16,'done','2026-04-22 21:00:53','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(134,'Chore: Plugin ''Gesundheit'' in ''Wohlbefinden'' umbenennen','core','Plugin ''Gesundheit'' in ''Wohlbefinden'' umbenennen für klare Abgrenzung zu ''Medikamente''. Betrifft: Plugin-Key, Labels, Navigation, API-Routen (Breaking Change), Tests.
INSERT INTO "backlog" VALUES(135,'Feature: Floating Action Button (FAB) für mobile Navigation','feature','Als mobiler Nutzer möchte ich einen fest positionierten FAB mit Plus-Symbol unten rechts, der alle Hinzufügen-Aktionen bündelt. Ersetzt oder ergänzt das bisherige Add-Menü auf Mobile.',3,NULL,17,'done','2026-04-22 21:00:53','2026-04-24 04:42:53',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(136,'Bug: Navigationsverhalten nach ''Abbrechen'' im Quick-Add-Dialog','bug','Nach dem Tippen auf ''Abbrechen'' in einem Quick-Add-Dialog auf dem Dashboard wird der Nutzer nicht zurück auf das Dashboard geleitet. Erwartetes Verhalten: Rückkehr zum Dashboard ohne Datenverlust.',2,NULL,15,'done','2026-04-22 21:00:53',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(137,'UX: Automatisch wachsendes Titelfeld in mobiler To-Do-Liste','feature','Das Eingabefeld für den Titel in der To-Do-Liste soll auf mobilen Geräten automatisch in der Höhe wachsen, wenn der eingegebene Text die erste Zeile überschreitet.',4,NULL,15,'done','2026-04-22 21:00:53','2026-04-23 21:07:22',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(138,'UX: Countdown statt Kindname beim Sprung-Indikator auf Dashboard','feature','Neben dem Indikator für den nächsten Sprung soll anstelle des Kindsnamens ein Countdown in Tagen angezeigt werden (''in 3 Tagen''). Kindname ist bereits im Header sichtbar.',4,NULL,15,'done','2026-04-22 21:00:53',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(139,'Fix: #27 Warnhinweise — Referenzwerte-Tabelle + Übernahme-UX + Abweichungswarnung','feature','Unter /admin/alerts: Button pro Warnregel öffnet Referenzwerte-Tabelle (altersabhängig). Eltern können Richtwert übernehmen → wird als Schwellwert eingetragen. Dashboard-Warnung wenn eingestellter Wert von Referenz abweicht. Warnung dismiss-bar + Option nicht mehr benachrichtigen.',2,'v0.7.1',NULL,'done','2026-04-24 06:22:38','2026-04-24 07:55:41',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(140,'Fix: #100 Tasks & Habits — Sidebar-Label + Dashboard-Kachel + 2 Admin-Toggles','bug','1) Sidebar-Label GEFIXT (nicht deployed). 2) Neue Dashboard-Kachel für Habits mit Fortschrittsbalken (X/Y heute erledigt). 3) /admin/plugins: 2 separate Dashboard-Toggles für ToDos und Habits.',2,'v0.7.1',NULL,'done','2026-04-24 06:22:38','2026-04-24 07:55:41',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(141,'Fix: #107 Changelog — Admin-UI zum Schreiben von Einträgen','feature','Neue Route /admin/changelog: Admin kann Changelog-Einträge erstellen/bearbeiten. Nur für Rolle App-Admin sichtbar. Ersetzt manuelle changelog.json-Pflege.',3,'v0.7.1',NULL,'done','2026-04-24 06:22:38','2026-04-24 06:45:20',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(142,'Fix: #135 FAB — Weitere-Button + altes Add-Menu entfernen','feature','FAB erhält zusätzliche Weitere-Schaltfläche → öffnet vollständiges Overlay (wie bisheriges + Neu). Danach: Add-Button und Quick-Actions aus Mobile-Ansicht entfernen. FAB wird einziger Einstiegspunkt auf Mobile.',2,'v0.7.1',NULL,'done','2026-04-24 06:22:38','2026-04-24 07:55:41',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(143,'Fix: #131 Markdown — Formatleiste wie Obsidian Mobile','feature','Formatierungshilfe-Leiste über der Tastatur (Obsidian-Mobile-Stil). Buttons: Bold, Italic, Heading, List, Checkbox, Code. Leiste erscheint bei Fokus auf Editor. Zielgruppe: Nicht-technische Nutzer ohne Markdown-Kenntnis.',3,'v0.7.1',NULL,'done','2026-04-24 06:22:38','2026-04-24 06:45:20',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(144,'Fix: #133 Medikamenten-Widget — weiterhin zu groß','bug','Nach Deploy erneut prüfen. Falls Widget-Größe immer noch nicht passt: row-span entfernen, padding weiter reduzieren, Einzeiler-Layout.',4,'v0.7.1',NULL,'done','2026-04-24 06:22:38','2026-04-24 06:45:20',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(145,'Feature: Live-Preview Markdown Editor (Obsidian-Stil)','feature','Aktuellen MarkdownEditor durch Library-basierten Live-Preview Editor ersetzen (z.B. @uiw/react-md-editor oder react-simplemde-editor). Cursor im formatierten Text zeigt Raw-Markdown, sonst gerendert — wie Obsidian. Betrifft: Notes, Habits, Todo-Details. Aktuelle 80%-Loesung (Toolbar + Textarea + Live-Preview) bleibt bis dahin.',3,'v0.8.0',19,'done','2026-04-24 07:38:57',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(146,'Fix: #110 U-Untersuchungen — Abhaken nicht möglich','bug','CheckupPage: Einträge können nicht als erledigt markiert werden. Completion-Flow prüfen (Checkbox/Button fehlt oder Endpoint fehlerhaft).',2,'v0.7.1',NULL,'done','2026-04-24 07:44:14','2026-04-24 07:55:41',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(147,'Fix: #117 Schlaf-Ort — Apple-Toggle statt HTML-Checkbox','bug','SleepForm location Toggle nutzt falschen Stil. Muss Apple-Toggle (iOS-Stil) verwenden wie im Rest der App (h-8, w-[52px], bg-green/bg-surface2, weißer Knob).',3,'v0.7.1',NULL,'done','2026-04-24 07:44:14','2026-04-24 07:55:41',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(148,'Fix: #130 Notizen — Tag-Support fehlt','bug','SharedNotes brauchen Tag-Support wie alle anderen Entitäten. TagSelector (bound+pending) in NoteForm, TagBadges in NoteList. Backend: entry_tags mit entry_type=note.',3,'v0.7.1',NULL,'done','2026-04-24 07:44:14','2026-04-24 07:55:41',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(149,'Fix: #107 Changelog Admin — Varianten + Styling + Markdown','bug','1) Varianten-Auswahl: Update (peach), Info (sapphire), Warnung (red). 2) Button Eintragen weiße Schrift schwer lesbar → Fix. 3) Feld Aenderungen in Text umbenennen. 4) Markdown im Text-Feld aktivieren.',3,'v0.7.1',NULL,'done','2026-04-24 07:44:14','2026-04-24 07:55:41',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(150,'Feature: U-Untersuchungen — Datumsbereich basierend auf Geburtstag anzeigen','feature','Neben dem empfohlenen Alter (z.B. 3.-10. Lebenstag) auch den konkreten Datumsbereich anzeigen, berechnet aus dem Geburtstag des Kindes. Eltern muessen nicht im Kopf umrechnen.',3,'v0.8.0',19,'done','2026-04-24 08:08:13',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(151,'Bug: Schlaferfassung — Timer-Stop erstellt keinen Eintrag','bug','Anna hat zwischen 08:15 und 10:08 geschlafen. Timer gestoppt, kein Schlaf-Eintrag wurde erstellt. Schlaf verloren.',1,'v0.8.0',19,'done','2026-04-24 13:38:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(152,'Bug: Schlaf-Timer sperrt Zugriff auf Schlafhistorie','bug','Während ein Schlaf-Timer läuft, können vergangene Schlafzyklen weder angesehen noch bearbeitet werden.',2,'v0.8.0',19,'done','2026-04-24 13:38:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(153,'Bug: Datumswechsel nachts — Fütterungen nach Mitternacht fehlen','bug','Fütterungen um 1 Uhr nachts werden zwar in der Summe (ml) gezählt, aber nicht in der Einzel-Auflistung angezeigt. Nur nach 6 Uhr sichtbar.',2,'v0.8.0',19,'done','2026-04-24 13:38:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(154,'Bug: Windel-Bezeichnung inkonsistent (Eingabe vs. Dashboard)','bug','Windel-Typ "beides" wird im Dashboard als andere Bezeichnung angezeigt als bei der Eingabe. Einheitlich auf "beides" setzen.',2,'v0.8.0',19,'done','2026-04-24 13:38:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(155,'Bug: Session-Cookie läuft ab — PWA zeigt keinen Login','bug','Wenn der Session-Cookie im Hintergrund abläuft, erkennt die PWA das nicht und zeigt keine Login-Aufforderung.',2,'v0.8.0',19,'done','2026-04-24 13:38:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(156,'Feature: Durchschnittswerte (7+14 Tage) auf Baby-Dashboard','feature','Durchschnittswerte je Entität (Schlaf, Mahlzeiten, Windeln) auch auf dem Baby-Dashboard unter 7 und 14 Tagen anzeigen.',3,'v0.8.0',19,'done','2026-04-24 13:38:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(157,'Feature: Notes — Suchfeld für Notizen-Übersicht','feature','Auf der /notes-Seite ein Suchfeld ergänzen, das Titel und Inhalt der Notizen filtert.',2,'v0.8.0',19,'done','2026-04-24 13:38:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(158,'Feature: Notes — Details eingeklappt (wie Tasks)','feature','In der Notizen-Übersicht sollen Details nicht vollständig angezeigt werden — Klick öffnet die Detailansicht, analog zur Task-Ansicht.',2,'v0.8.0',19,'done','2026-04-24 13:38:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(159,'Feature: Notes — Titel visuell stärker hervorheben (wie Tasks)','feature','Notiz-Titel in der Listenansicht salienter gestalten — Schriftgröße, Gewicht oder Layout an die Task-Ansicht angleichen.',3,'v0.8.0',19,'done','2026-04-24 13:38:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(160,'Feature: Meilensteine — Foto-Upload UI (Backend vorhanden)','feature','Backend bereits implementiert (router.py, data/uploads/). Frontend-Upload-UI fehlt: Foto-Picker in Meilenstein-Detail, Thumbnail-Anzeige, Vollbild per Tap. Max 3 Fotos je Meilenstein. Server-seitige Thumbnail-Generierung via Pillow. Static-Mount /uploads/ durch Auth-gesicherten Proxy-Endpunkt ersetzen: GET /api/v1/milestones/photos/{filename}.',2,'v0.9.0',20,'done','2026-04-24 13:38:23',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(161,'Feature: Meilensteine — Timeline mit Fotos','feature','Eigene Route /milestones/timeline. Vertikale Zeitleiste, chronologisch sortiert nach achieved_date. Foto mittig, Datum darunter (Alter in Wochen/Monaten). Meilenstein-Titel alternierend links/rechts. Kein Foto: Placeholder mit Kategorie-Icon. Lazy-Loading der Thumbnails. Swipe-to-Fullscreen.',2,'v0.9.0',20,'done','2026-04-24 13:38:23',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(162,'Feature: Medienverwaltung in Admin','feature','Route /admin/media. Grid-Übersicht aller Fotos nach Kind/Zeitraum/Kategorie filterbar. Aktionen: Herunterladen (original), Ersetzen, Löschen. Bulk-Auswahl + ZIP-Download (synchron). Speicherplatz-Anzeige. Datensouveränität: volle Kontrolle über eigene Medien.',2,'v0.9.0',20,'done','2026-04-24 13:38:23',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(163,'Research: Foto-Integration — Architektur und UX-Konzept','core','Entscheidungen getroffen (2026-04-24): 3 Fotos max, Pillow-Thumbnails, ZIP synchron, Route /milestones/timeline, /uploads/ Auth-gesichert. Details: docs/research/2026-04-24-foto-integration-analyse.md. Backend-Task: Photo-Proxy-Endpunkt + Thumbnail-Pipeline. Bestehenden Static-Mount ablösen.',1,'v0.9.0',20,'done','2026-04-24 13:38:23',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(164,'Feature: CodeMirror 6 WYSIWYG Markdown-Editor (Obsidian-Stil)','feature','Ersetze den aktuellen Split-View/Toggle Markdown-Editor durch einen CodeMirror 6 WYSIWYG-Editor.
INSERT INTO "backlog" VALUES(165,'Feature: Notes — Expand/Collapse Details (wie Tasks)','feature','Notes-Details müssen per Klick aufklappbar sein, analog zur TodoList. line-clamp-2 als Vorschau, Klick auf den Eintrag expandiert den Volltext. Ohne Edit-Modus lesbar.',2,NULL,21,'done','2026-04-24 17:56:28',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(166,'Bug: Notes — Tags/Stichwörter anhängen funktioniert nicht','bug','Tags können Notizen nicht zugeordnet werden. Kein Effekt, kein Fehler. TagSelector prüfen — möglicherweise fehlt die Anbindung im Notes-Plugin (polymorphes Tagging für entry_type=note).',1,NULL,21,'done','2026-04-24 17:56:28',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(167,'Feature: Meilensteine Übersicht — Quick-Photo-Upload bei fälligen Meilensteinen','feature','In Meilensteine > Übersicht soll bei fälligen Meilensteinen ein Foto-Piktogramm erscheinen. Klick/Tap öffnet den Medienbrowser zur Auswahl. Aktueller Workflow (Abhaken → Alle → Foto) ist zu umständlich. Direkter Upload-Flow in der Übersicht.',2,NULL,21,'done','2026-04-24 17:56:28',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(168,'Feature: Meilensteine Timeline — Foto-Upload direkt in Timeline','feature','In der Meilenstein-Timeline soll bei jedem Eintrag ein Foto hochgeladen werden können (analog PhotoSection). Aktuell nur in der Detailansicht möglich.',2,NULL,21,'done','2026-04-24 17:56:28',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(169,'Feature: Meilenstein-Fotos — Tags/Stichwörter für Bilder','feature','Bilder/Fotos sollen Tags zugeordnet werden können (polymorphes Tagging auf milestone_photos). Tag-Option muss ausgeblendet sein, wenn das Tag-Plugin deaktiviert ist (pluginConfig Check).',2,NULL,21,'done','2026-04-24 17:56:28',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(170,'Feature: In-App Tutorial — Overlay-Framework (Spotlight + Tooltip + Navigation)','feature','Overlay-System: Hintergrund abdunkeln, aktives Element hervorheben (Spotlight). Tooltip-Schicht mit Erklaertext, Vor/Zurueck-Pfeil-Navigation und Skip-Tutorial-Button. Step-Sequenz-Controller in React (Context oder Zustand). localStorage-Persistenz: tutorial_completed + tutorial_step. Erste Aktivierung: automatisch beim ersten Dashboard-Aufruf nach Login. Keine externe Tutorial-Lib — eigene React-Komponenten. Catppuccin-Styling konsistent mit App.',2,'v0.9.0',NULL,'refined','2026-04-24 18:05:06',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(171,'Feature: In-App Tutorial — Interaktive Schritte mit Action Detection','feature','Tutorial-Steps fordern Nutzer aktiv auf, eine Aktion durchzufuehren (z.B. FAB antippen, Eintrag speichern, Plugin-Seite aufrufen, Dashboard-Tab wechseln). Frontend erkennt die Aktion via Event-Listener oder State-Watch und setzt das Tutorial automatisch fort ohne manuellen Klick auf Weiter. Ziel: Muskelgedaechtnis einueben. Interaktive Steps definieren: 1) FAB oeffnen 2) Eintrag erstellen + speichern 3) Naechsten Tab waehlen 4) Plugin-Verwaltung aufrufen 5) Quick-Action benutzen.',2,'v0.9.0',NULL,'refined','2026-04-24 18:05:06',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(172,'Feature: In-App Tutorial — Plugin-Beschreibungen auf /admin/plugins','feature','Jedes Plugin auf der Plugin-Verwaltungsseite erhaelt einen Beschreibungstext (1-2 Saetze: was wird getrackt, fuer wen geeignet). Anzeige als ausklappbare Beschreibung unter dem Plugin-Namen oder als Info-Icon mit Tooltip. Texte in i18n de + en. Betrifft: sleep, feeding, diaper, vitamind3, temperature, weight, medication, todo, health, tummytime, milestones, growth, checkup, notes (14 Plugins).',3,'v0.9.0',NULL,'refined','2026-04-24 18:05:06',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(173,'Feature: In-App Tutorial — Reset ueber Profil + Tutorial-State in UserPreferences','feature','ProfilePage (/profile): Schaltflaeche Tutorial neu starten. Klick setzt tutorial_completed=false, navigiert zu /dashboard, Tutorial startet von Schritt 1. UserPreferences um tutorial_completed (Boolean) und tutorial_step (Integer) erweiterern (Alembic Migration). Backend-Persistenz stellt sicher, dass Tutorial-State nach Browser-Wechsel korrekt bleibt. Bestehender GET/PATCH /preferences Endpunkt nutzen.',3,'v0.9.0',NULL,'refined','2026-04-24 18:05:06',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(174,'Bug: Changelog-Eintrag erfassen — API 500 Internal Server Error','bug','POST auf Changelog-Endpunkt schlaegt mit HTTP 500 fehl: {"detail":"Internal server error","error_code":"INTERNAL_ERROR"}. Ursache unbekannt — Backend-Log pruefen. Moeglicherweise fehlendes Pflichtfeld, Schema-Validierungsfehler oder DB-Constraint-Verletzung im Changelog-Router.',1,NULL,NULL,'done','2026-04-24 18:56:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(175,'Bug: Aktueller Changelog-Eintrag erscheint nicht in der Liste','bug','Nach erfolgreichem Anlegen eines Changelog-Eintrags (oder beim Oeffnen der Changelog-Uebersicht) wird der aktuelle Eintrag nicht in der Liste angezeigt. Moeglicherweise falscher Sortierfilter, fehlende Invalidation des Frontend-Cache, oder die Liste filtert nach einer Bedingung (z.B. nur veroeffentlichte Eintraege) die den neuen Eintrag ausschliesst.',2,NULL,NULL,'done','2026-04-24 18:56:11',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(176,'Tagesverlauf: Laufender Schlaftimer als grüner Balken anzeigen','feature','Wenn ein Schlaftimer aktiv ist, soll der aktuelle Schlafzeitraum (ab Timer-Start bis jetzt) als grüner Balken im Tagesverlauf-Diagramm dargestellt werden. Das hilft, die Relation der aktuellen Schlafdauer zu den bisherigen Schlafphasen visuell zu erkennen. Abgeschlossene Schlafphasen bleiben in der bisherigen Farbe (mauve/lila).',3,NULL,NULL,'refined','2026-04-24 20:25:13',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(177,'Dashboard Habits-Widget: Wochentag-Filter anwenden','bug','Das Habits-Widget im Dashboard zeigt alle Habits unabhängig vom Wochentag (z.B. 3/4 statt 3/3 am Freitag). Die Wochentag-Filterlogik aus /todo (HabitList.tsx) muss auch im Dashboard-Widget angewendet werden, sodass nur die für den aktuellen Wochentag relevanten Habits gezählt und angezeigt werden.',2,NULL,NULL,'done','2026-04-24 20:26:13',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(178,'Stillmodus: Von Benutzer-Einstellung zu Kind-spezifischer Einstellung migrieren','feature','Der Stillmodus ist aktuell global/benutzerspezifisch (UserPreferences + localStorage). Er sollte kind-spezifisch sein, da ein Kind gestillt werden kann und ein anderes nicht. Änderungen: 1) breastfeeding_enabled aus UserPreferences entfernen, 2) Feld in Child-Model oder ChildConfig aufnehmen, 3) Toggle aus /profile und /admin entfernen, 4) Toggle in Kind-Verwaltung (/admin > Kinder) oder Kind-Detail verschieben, 5) Frontend-Logik (BabySummary, FeedingForm) auf activeChild.breastfeeding_enabled umstellen.',3,NULL,NULL,'refined','2026-04-24 20:28:55',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(179,'Profil-Link: Von Sidebar in den Header verschieben','feature','Der Profil-Link soll aus der Sidebar entfernt und stattdessen im Header neben dem Aktualisieren-Button platziert werden (z.B. als User-Avatar/Icon). Das entspricht dem erwartungskonformen UX-Pattern moderner Web-Apps. Betrifft: Header.tsx (Icon hinzufügen), Sidebar.tsx (Link entfernen), MobileMenu ggf. anpassen.',3,NULL,NULL,'done','2026-04-24 20:29:29','2026-04-25 18:54:20',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(180,'Header: Benachrichtigungs-Glocke mit Alert-Badge','feature','Im Header eine Glocke (Bell-Icon) anzeigen, die einen roten Punkt/Badge zeigt wenn aktive Warnungen vorhanden sind. Klick öffnet ein Dropdown/Panel mit den aktuellen Warnungen. Dismiss-Status wird zwischen Dashboard-AlertBanner und Header-Glocke synchronisiert (gleicher localStorage-Key). Betrifft: Header.tsx (Bell-Icon + Badge), AlertBanner-Logik als shared Hook extrahieren, Dismiss-State teilen.',3,NULL,NULL,'done','2026-04-24 20:30:50',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(181,'Header-Redesign: Verwaltung in Header, Theme-Toggle ins Profil','feature','Verwaltungs-Link (Settings-Icon) aus Sidebar in den Header verschieben, ersetzt den Theme-Toggle. Der Theme-Wechsel wird ins Profil-Menü (/profile) verschoben, da es eine Benutzereinstellung ist. Header-Reihenfolge z.B.: [Titel] ... [Glocke] [Verwaltung] [Profil] [Aktualisieren]. Betrifft: Header.tsx (Verwaltungs-Icon statt Theme-Toggle), Sidebar.tsx (Verwaltungs-Link entfernen), ProfilePage.tsx (Theme-Toggle hinzufügen).',3,NULL,NULL,'refined','2026-04-24 20:31:43',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(182,'Dashboard umbenennen in Home mit Haus-Icon','feature','Dashboard-Seite und Navigation umbenennen: Label "Dashboard" → "Home", Icon von LayoutDashboard → Home (Lucide). Betrifft: BottomNav, MobileMenu, Sidebar, Header-Titel, Route kann /dashboard bleiben oder zu / wechseln.',4,NULL,NULL,'refined','2026-04-24 20:32:27',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(183,'Bug: Sprachwechsel zu Englisch auf /profile schlägt fehl','bug','Auf der Profilseite führt die Änderung der Sprache von Deutsch zu Englisch zum Fehler "Speichern fehlgeschlagen". Ursache untersuchen: PATCH /api/v1/preferences oder /api/v1/auth/me mit locale-Feld, mögliche Validierung oder DB-Constraint.',2,NULL,23,'done','2026-04-24 20:32:50','2026-04-25 21:38:58',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(184,'Sidebar-Navigation: Reihenfolge thematisch sortieren','feature','Die Navigationseinträge in der Sidebar wirken chaotisch. Thematisch sinnvoll gruppieren, z.B.: Home → Tracking (Schlaf, Mahlzeiten, Windeln, Gesundheit, Bauchlage) → Entwicklung (Meilensteine, Wachstum, U-Untersuchungen) → Organisation (Tasks, Notizen, Tags) → ggf. visuelle Trennlinien/Gruppenheader. Auch MobileMenu/BottomNav entsprechend anpassen.',3,NULL,NULL,'refined','2026-04-24 20:33:46',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(185,'FAB: 4 Quick-Actions als Radial-Menü','feature','Quick-Actions von 3 auf 4 erweitern. FAB öffnet sich als Rad/Radial-Menü (statt linear), 4 Einträge kreisförmig um den Button angeordnet. FAB bleibt Mobile-only (< md) — auf Desktop übernehmen Header-Icons und Sidebar die Navigation. UserPreferences.quick_actions Array von 3 auf 4 erweitern. Betrifft: FAB-Komponente (Animation/Layout), ProfilePage (4. Slot konfigurierbar), UserPreferences Backend (Validierung anpassen).',4,NULL,NULL,'refined','2026-04-24 20:34:38',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(186,'Bug: Navigation Habit Widget — Klick navigiert nicht korrekt','bug','MyBaby Todo #12: Navigation Habit Widget — aus user-reported Todo-Liste',2,NULL,23,'done','2026-04-25 20:43:05','2026-04-25 21:42:19',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(187,'Bug: Habits Dashboard — falsche Zählung aktiver Habits','bug','MyBaby Todo #13: Habits werden mehr gezählt als täglich aktiv sein sollten (z.B. sonntags-only Habits werden mitgezählt)',2,NULL,23,'done','2026-04-25 20:43:05','2026-04-25 21:46:42',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(188,'Smoke-Test: Setup-Validierung','bug','Smoke-Test: Setup-Validierung',3,NULL,NULL,'new','2026-04-25 20:52:20',NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "backlog" VALUES(189,'Test-Issue Phase2','bug',NULL,3,NULL,NULL,'cancelled','2026-04-26 06:46:28','2026-04-26 06:46:42',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "conversation_snapshots" VALUES(1,'brainstorming-session','2026-04-19 13:37:05','Architektur-Design abgeschlossen. FastAPI + SQLite + React/TS. 7 ADRs entschieden. Review mit 4 kritischen + 8 wichtigen Findings — alle in Spec eingearbeitet. Plan mit 14 Tasks erstellt.','["FastAPI statt NestJS/Fastify", "Standalone statt Home-Dashboard-Integration", "CLI+MCP statt Telegram-Plugin", "TypeScript Frontend", "UTC-only Timestamps"]','Repo klonen, Task 1 starten, Projektstruktur aufsetzen');
INSERT INTO "conversation_snapshots" VALUES(2,'scrum-master','2026-04-19 13:47:40','Sprint 1 "MVP v0.1.0" geplant und aktiviert. 14 Tasks aus Backlog-Items erstellt. Reihenfolge: Infrastruktur (Tasks 1-4) -> Security (5) -> App Factory (6) -> Plugins (7-9) -> Frontend (10-11) -> Deployment (12) -> Import/Docs (13-14). Gesamtaufwand: 63 Story Points.','["14 Tasks mit Story-Point-Schaetzungen erstellt","Sprint auf active gesetzt","Reihenfolge: Core/Infra vor Features vor UI vor Deployment","Security-Task (K1-K4) als eigener Block vor App Factory"]','Coding-Lead mit Task 1 (Repo Setup) starten. Nach jedem Task: Code-Review + Test durch spezialisierte Agenten.');
INSERT INTO "conversation_snapshots" VALUES(3,'coding-lead','2026-04-19 14:01:09','Task 1: Repo Setup + Project Scaffolding abgeschlossen. Backend (FastAPI, SQLAlchemy, Alembic, structlog, pydantic-settings) und Frontend (React 18, TypeScript, Vite 6, Tailwind 3, Catppuccin) scaffolded. Health-Endpoint mit 2 Tests verifiziert (PASSED). Docker multi-stage Dockerfile und docker-compose.yml erstellt. .env.example mit allen Env-Vars.','Python 3.14 als Runtime (venv). build-backend: setuptools.build_meta. Token ground statt base fuer Tailwind.','Task 2: Core Config + Logging + Database implementieren.');
INSERT INTO "conversation_snapshots" VALUES(4,'coding-lead','2026-04-19 14:09:37','Task 2: Core Config + Logging + Database abgeschlossen. config.py erweitert (CSRF, Rate Limit, Environment, CORS list, Literal-Typen). Neue logging.py (structlog JSON/UTC). database.py auf async (aiosqlite, AsyncSession, WAL). main.py integriert setup_logging + get_logger. 20/20 Tests gruen.','["Dateien bleiben in app/ statt app/core/", "Sync DB auf async umgebaut", "greenlet als explizite Dependency"]','Task 3: Core Models + Alembic Migrations');
INSERT INTO "conversation_snapshots" VALUES(5,'coding-lead','2026-04-19 14:14:36','Task 3 abgeschlossen: Core Models (User, Child, ChildCaregiver) + TimestampMixin + Alembic Migration. 31/31 Tests bestanden. Doppelte Base in database.py konsolidiert.','["Base-Klasse nur in models/base.py (Single Source)", "PluginState/AuditLog nicht im Scope von Task 3", "render_as_batch=True fuer SQLite ALTER TABLE"]','Task 4: Plugin SDK Base Class + Discovery');
INSERT INTO "conversation_snapshots" VALUES(6,'coding-lead','2026-04-19 14:18:40','Task 4 done: Plugin SDK Base Class + Discovery. PluginBase ABC (_base.py) with __init_subclass__ validation, WidgetDef dataclass, PluginRegistry (registry.py) with register/discover/get/get_all, filesystem auto-discovery via pkgutil. __init__.py updated with discover_plugins() + discover_models(). main.py lifespan integration with startup/shutdown hooks. 18 new tests, 49 total passing.','["Kept modules under app/ (not app/core/) to match existing structure", "Used __init_subclass__ for class-attribute validation instead of metaclass", "PluginRegistry as class (not module-level dict) for testability"]','Task 5: Sleep Plugin (Backend) — first real plugin using the SDK');
INSERT INTO "conversation_snapshots" VALUES(7,'coding-lead','2026-04-19 14:24:44','Task 5: Auth Middleware + Security Hardening. Implemented K1 header stripping, K2 CSRF+CSP headers, K3 request size limit, auth middleware (forward/local/disabled), Argon2 hashing, rate limiting, require_role. Files: security.py, csrf.py, auth.py, rate_limit.py (all NEW), updated main.py + config.py + __init__.py. 20 new tests, 69 total passing.','["trust_all param on HeaderStrippingMiddleware for test isolation","CSRF disabled in testing mode via create_app(testing=True)","Middleware order: HeaderStripping > CSRF > RequestSizeLimit > SecurityHeaders"]','Task 6: implement first plugin (feeding/nursing) using auth dependencies');
INSERT INTO "conversation_snapshots" VALUES(8,'coding-lead','2026-04-19 14:29:45','Task 6 done: App Factory vervollstaendigt (CORS, Error Handlers, OpenAPI, /api/v1/ prefix). Health-Endpoint, Children CRUD Router, Pydantic Schemas mit K3-Constraints, Custom Error Handling. 88 Tests bestanden (22 neue Tests).','["Health unter /api/v1/health ohne Auth", "Children CRUD unter /api/v1/children/ mit Auth", "Soft-Delete statt Hard-Delete", "Globaler Exception-Handler fuer JSON-Error-Format"]','Task 7: Sleep Plugin implementieren');
INSERT INTO "conversation_snapshots" VALUES(9,'coding-lead','2026-04-19 14:34:40','Task 8: Feeding Plugin Backend implementiert. 6 Dateien erstellt (models, schemas, router, widget, __init__, tests). 23 Tests alle gruen (CRUD 8, Filter 3, Validation/K3 6, FeedingTypes 6).','["FeedingEntry mit relationship zu Child via backref", "Literal type fuer feeding_type Validation statt DB-Enum", "Model-Import in Tests noetig fuer create_all"]','Task 7 (Sleep Plugin) parallel abschliessen, dann Merge und Alembic Migration');
INSERT INTO "conversation_snapshots" VALUES(10,'coding-lead','2026-04-19 14:34:59','Task 9: Diaper Plugin (Backend) implementiert. 6 Dateien erstellt in backend/app/plugins/diaper/ + backend/tests/test_diaper_plugin.py. 19/19 Tests bestanden: CRUD, Filter (child_id, diaper_type, date_from, date_to), Validation (max_length, Enum), Boolean has_rash, Plugin-Klasse.','["DiaperType als str Enum (wet/dirty/mixed/dry)", "Widget: size=small, name=diaper_summary", "Router-Prefix: /api/v1/diaper", "Keine gemeinsamen Dateien geaendert (parallel zu Task 7+8)"]','Frontend Diaper Plugin, Alembic Migration nach Merge aller Plugins');
INSERT INTO "conversation_snapshots" VALUES(11,'coding-lead','2026-04-19 14:35:40','Task 7: Sleep Plugin (Backend) implementiert. 20/20 Tests bestanden. Plugin: models, schemas, router, widget. Alembic-Migration generiert. conftest.py gefixt: Plugin-Routes im async_client Fixture. env.py: discover_models() hinzugefuegt.','["K3 constraints auf allen Schemas", "Duration-Berechnung mit naive/aware Normalisierung", "conftest discover_plugins fuer alle Plugin-Tests"]','Task 8 oder Diaper-Plugin-Tests fixen (vorbestehend fehlgeschlagen)');
INSERT INTO "conversation_snapshots" VALUES(12,'coding-lead','2026-04-19 16:10:08','Task 10 done: Frontend Shell + Core Components. 28 Dateien erstellt/geaendert. API Client (CSRF), TS-Interfaces, 11 Components, 5 Pages, Router, React Query, ChildContext, useTheme. Build OK, 23/23 Tests passed.','["Vitest + jsdom als Test-Env", "matchMedia mock im setup.ts", "data-theme Attribut fuer manuellen Theme-Toggle", "localStorage mock fuer useTheme Tests"]','Task 11: Frontend Plugin Components (Sleep/Feeding/Diaper Forms + Widgets portieren)');
INSERT INTO "conversation_snapshots" VALUES(13,'coding-lead','2026-04-19 16:18:30','Task 11: Frontend Plugin Components complete. Created 3 API modules, 3 React Query hooks, 9 plugin components (Form+List+Widget x3), dateUtils lib. Updated Dashboard with widget grid + quick actions, 3 pages with form+list. Updated types.ts with missing fields. 51 tests pass, build clean.','["Added location+duration_minutes to SleepEntry type","Added SleepUpdate/FeedingUpdate/DiaperUpdate interfaces","Used Intl.DateTimeFormat for UTC-to-local conversion","Inline form toggle pattern for pages (not modal)","Color buttons as visual preset selection for diaper form"]','Task 12+: Integration tests, E2E, plugin registry if needed');
INSERT INTO "conversation_snapshots" VALUES(14,'coding-lead','2026-04-19 16:23:16','Task 12 Docker Deployment abgeschlossen. Dockerfile (multi-stage, non-root, healthcheck), docker-compose.yml (prod), docker-compose.dev.yml (hot-reload), portainer-stack.yml (NAS), .env.example, .dockerignore erstellt. main.py erweitert: Alembic auto-migration, StaticFiles + SPA fallback. 150 Backend + 51 Frontend Tests bestanden.','["Port 8000 intern statt 8080","Non-root User mybaby","curl healthcheck statt python","Alembic auto-migration bei Startup","SPA fallback mit path-traversal Schutz"]','Task 13: Baby Buddy Import Script. Danach manuelles Deployment auf NAS testen.');
INSERT INTO "conversation_snapshots" VALUES(15,'coding-lead','2026-04-19 16:28:17','Task 13: Baby Buddy Import Script implementiert. Typer CLI (scripts/import_babybuddy.py) mit async httpx + SQLAlchemy. Mapping BB->MyBaby fuer children, sleep, feeding, diaper. Features: Pagination, Duplicate Detection, Dry-Run, Error Handling, Summary. 30 Tests in test_import.py. Alle 180 Backend-Tests gruen.','["Script nutzt sync SQLAlchemy Engine fuer Import statt async App-Infrastruktur","Mapping: breast milk + method -> breast_left/breast_right, formula/fortified -> bottle, solid food -> solid","Duplicate Detection via child_id + start_time/time"]','Task 14 oder Frontend-Portierung');
INSERT INTO "conversation_snapshots" VALUES(16,'coding-lead-final','2026-04-19 16:31:06','Sprint 1 MVP v0.1.0 complete. All 14 tasks done. 180 backend + 51 frontend tests passing. Commit b7023bb pushed to origin/main. Ready for deployment.','["Final commit includes frontend, docker, import, tests"]','["Deploy to NAS via Portainer", "Manual testing on baby.familie-riedel.org", "Baby Buddy data import"]');
INSERT INTO "conversation_snapshots" VALUES(17,'scrum-master','2026-04-20 04:54:50','Sprint 2 geplant und aktiviert. 19 Tasks, 47 SP, 7 Backlog-Items. v0.1.0 Backlog auf done gesetzt. 6 neue Backlog-Items fuer v0.2.0 angelegt. Reihenfolge: Temperatur > Gewicht > Medikamente > Warnhinweise > BottomNav > EntryListOverlay.','["ADR-8: Plugin-Reihenfolge (Temperatur zuerst)", "ADR-9: VitaminD3 bleibt eigenstaendig", "ADR-10: Konfigurierbare Warnschwellwerte"]','Task 15: Temperatur Backend Model + Migration starten. TDD-Workflow mit Coding Lead Agent.');
INSERT INTO "conversation_snapshots" VALUES(18,'scrum-master','2026-04-20 05:14:26','Sprint 2 abgeschlossen. 19/19 Tasks done. 3 neue Plugins (temperature, weight, medication), Warnhinweise-System mit konfigurierbaren Schwellwerten (ADR-10), adaptives BottomNav (4+Mehr), AlertBanner. 268 Backend + 49 Frontend = 317 Tests. EntryListOverlay auf v0.3.0 verschoben.','["ADR-8: Plugin-Reihenfolge", "ADR-9: VitaminD3 bleibt eigenstaendig", "ADR-10: Konfigurierbare Warnschwellwerte"]','Commit + Push, Portainer Redeploy, visuelles Testing der neuen Plugins und Warnhinweise.');
INSERT INTO "conversation_snapshots" VALUES(19,'scrum-master-sprint3','2026-04-20 13:45:27','Sprint 3 v0.3.0: Medikamenten-Stammdaten (MedicationMaster Model + CRUD API + FK + Dropdown), Temperatur +/- Stepper-Buttons, Dashboard Timer Start/Stop, Untertemperatur-Warnung < 36.5, Pflichtfelder *, Konsistenz-Feld entfernt, ViewTabs visuell getrennt. 278 Backend-Tests + 47 Frontend-Tests. 15 Tasks.','["ADR: MedicationMaster als eigenstaendiges Model (nicht Plugin)", "Konsistenz-Feld bei Windeln entfernt (User-Feedback)"]','Sprint 4 planen: v0.4.0 Tag-System + Baby ToDo-Liste');
