INSERT INTO "conversation_snapshots" VALUES(29,'coding-lead','2026-04-22 03:37:38','Sprint 12 (v0.6.0): Auth-System komplett — JWT Login, Forward-Auth SSO, 2FA TOTP, Passkeys WebAuthn, Auth Settings UI. 6/6 Items done, 6 Commits, 2 Migrationen (totp_secrets, webauthn_credentials), 26 Auth-Tests bestanden.','["JWT in httpOnly Cookie (secure nur in prod)","LoginResponse mit requires_totp Signal fuer 2-Step-Login","TOTP Backup-Codes SHA256-gehasht (8 Stueck)","WebAuthn Challenge in Cookie (5min TTL)","AuthGuard: disabled+forward ohne Login, local+both mit LoginPage"]','User-Testing Auth auf NAS (Migration noetig), Frontend-Tests fuer Auth-Komponenten, Pre-existing test failures fixen');
INSERT INTO "conversation_snapshots" VALUES(30,'coding-lead','2026-04-22 04:37:55','Sprint 13 (v0.6.1): Nutzerverwaltung + Einstellungen. 3/3 Items done, 4 Commits. User CRUD API (admin-only), UserManagementPage, User timezone, UserPreferences Model (breastfeeding, quick_actions, widget_order, track_visibility), ProfilePage, Preferences API. 35 Auth-Tests, 2 Migrationen (timezone, user_preferences).','["Preferences serverseitig statt localStorage","ProfilePage unter /profile statt in Admin","timezone default Europe/Berlin","Auto-create Preferences bei erstem GET"]','Deploy Sprint 12+13 auf NAS (3 Migrationen), AUTH_MODE=forward umstellen, Erik+Julia testen');
