INSERT INTO "conversation_snapshots" VALUES(47,'scrum-master','2026-04-25 21:24:35','Sprint 23 (Bug-Fixing) review: bereits aktiv mit 3 Tasks (#168/#169/#170, je 1 PT). Backlog-Items #183/#186/#187 nachträglich mit assigned_sprint=23 verknüpft. Plan + Coding-Prompts in Run ca6476d2... geschrieben. Kein neuer Sprint nötig.','Backlog-assigned_sprint=23 für #183/#186/#187 gesetzt. Keine neuen ADRs.','coding-lead startet #168 → #169 → #170. validation_output je Task pflegen. Hinweis: Commit 3fb712e könnte #170/Backlog #187 bereits abdecken — Vorabprüfung. Nach #170 Snapshot, dann Scrum-Master setzt sprints.status=review_ready.');
INSERT INTO "conversation_snapshots" VALUES(48,'scrum-master','2026-04-25 21:25:08','Sprint #23 (Bug-Fixing) Session-Abschluss: Sprint bereits aktiv, kein neuer Sprint nötig. Tasks #168/#169/#170 (je 1 PT) bleiben todo. Backlog-Items #183/#186/#187 nachträglich mit assigned_sprint=23 verknüpft (vorher unset). Plan + Coding-Prompts geschrieben. Artifacts: /Users/erik/.archon/workspaces/xRiErOS/myPrivateBabyTracker/artifacts/runs/ca6476d2f213820fd3fabc3e740cda63','[]','coding-lead startet Tasks #168 → #169 → #170. Vorabprüfung Task #170: Commit 3fb712e (Wochentag-Filter Habits-Widget #177) könnte Backlog #187 bereits abdecken — falls ja, validation_output mit Commit-Hash + Begründung füllen, Status done. Nach Task #170: Snapshot durch coding-lead, danach Scrum-Master setzt sprints.status=review_ready.');
INSERT INTO "conversation_snapshots" VALUES(49,'po-dashboard-extend','2026-04-25 21:26:22','Run 71b1bcfd: Dashboard Dark Mode + Catppuccin-Tokens (DESIGN.md-konform). Geänderte Dateien: _dashboard/src/index.css ([data-theme="dark"]-Block + Macchiato-Tokens), _dashboard/src/components/Layout.jsx (Theme-State + localStorage + Toggle-Button mit Sun/Moon-Unicode). Workflow scheiterte am notify-Node (archon workflow list --format id existiert nicht), Notify-Code in allen 5 Workflows auf ${RUN_ID:-unknown} umgestellt. Dashboard-Code bleibt untracked (lokales Tool laut Konvention). User hat manuell verifiziert: Dashboard passt.','["notify-Node nutzt $RUN_ID, nicht archon workflow list", "_dashboard/ bleibt untracked, nur .gitignore-Defensive ergänzt", "Variante a: Dashboard lokal lassen, kein Commit"]','Sprint 23 ausführen via mybaby-sprint-execute (außerhalb Claude Code). Tasks #168 (Sprachwechsel /profile) → #169 (Habit-Widget Nav) → #170 (Habit-Wochentag-Zählung). Vorher: separater Commit für .archon/ + ARCHON.md.');
INSERT INTO "conversation_snapshots" VALUES(50,'scrum-master','2026-04-25 21:34:16','Sprint #23 Bug-Fixing aktiv mit 3 getaskten Bugs (#168 in_progress, #169, #170 todo). Backlog gepruft — keine Duplikate, keine DB-Schreibzugriffe noetig. Artefakte erstellt: plan.md mit Akzeptanzkriterien je Task + coding-prompts.md mit TDD-Workflow + Reihenfolge #168 -> #169 -> #170. Tasks #168 (Sprachwechsel /profile, Backlog #183), #169 (Habit-Widget Nav, #186), #170 (Habit-Zaehlung Wochentag-Filter, #187). Artifacts: /Users/erik/.archon/workspaces/xRiErOS/myPrivateBabyTracker/artifacts/runs/77c69b8cec02aac436b7760b4388ceea',NULL,'coding-lead startet Sprint 23: Task #168 (Sprachwechsel) zuerst — PATCH /api/v1/preferences debuggen, dann #169 (Routing zu /todos?tab=habits), dann #170 (Wochentag-Filter im Habit-Counter). Pro Task TDD + Commit + validation_output. Lokal: vite.config.ts vor Commit auf localhost:8080 zuruecksetzen.');
INSERT INTO "decisions" VALUES(1,'ADR-1: Plugin Registry','Filesystem scan with PluginBase base class','Entry-points for installable packages, config-file redundant. Pattern: Home Assistant, Datasette.','Entry-points, Config-file','active','2026-04-19 13:37:05');
INSERT INTO "decisions" VALUES(2,'ADR-2: Frontend Plugin Integration','Build-time single bundle with React.lazy()','Module Federation too complex, iFrames break shared state/theme.','Module Federation, iFrames','active','2026-04-19 13:37:05');
INSERT INTO "decisions" VALUES(3,'ADR-3: Data Model Separation','Plugin-owned tables with naming convention','Typed queries, DB validation, proper indexing. Generic event schema loses type safety.','Generic event schema','active','2026-04-19 13:37:05');
INSERT INTO "decisions" VALUES(4,'ADR-4: API Style','REST with auto-generated OpenAPI','AI-first: schema = tool definition. GraphQL overkill, tRPC needs TS backend.','GraphQL, tRPC','active','2026-04-19 13:37:05');
INSERT INTO "decisions" VALUES(5,'ADR-5: Event Bus','In-memory Pub-Sub (asyncio)','2-10 users, no retry needed. Upgrade to Redis later if needed.','DB-backed queue','active','2026-04-19 13:37:05');
INSERT INTO "decisions" VALUES(6,'ADR-6: PWA Offline','MVP without offline, later Last-Write-Wins','CRDTs overkill for sequential baby events.','CRDTs, Append-only log','active','2026-04-19 13:37:05');
INSERT INTO "decisions" VALUES(7,'ADR-7: Plugin Versioning','Monorepo version + API level integer','Single repo/release/container. Independent versioning = over-engineering.','Semver per plugin','active','2026-04-19 13:37:05');
INSERT INTO "decisions" VALUES(8,'ADR-8: Plugin-Reihenfolge Sprint 2','Temperatur zuerst (Pattern-Setter), dann Gewicht (Copy-Pattern), dann Medikamente (komplexer). Warnhinweise nach Plugins.','Temperatur ist das einfachste Plugin und etabliert das Copy-Paste-Pattern fuer weitere. Warnhinweise lesen Plugin-Daten und muessen daher nach den Plugins kommen.','["Alle parallel", "Medikamente zuerst"]','active','2026-04-20 04:54:50');
INSERT INTO "decisions" VALUES(9,'ADR-9: VitaminD3 bleibt eigenstaendiges Plugin','VitaminD3 wird NICHT vom Medikamenten-Plugin abgeloest. Es bleibt als eigenes Plugin bestehen.','VitaminD3 gilt fuer jedes Kind und wurde als Welle-1-Plugin implementiert. Es hat eine eigene UX (Kalender-Ansicht, daily-check). Das Medikamenten-Plugin deckt ad-hoc Medikamente ab.','["VitaminD3 als Spezialfall von Medikament migrieren"]','active','2026-04-20 04:54:50');
INSERT INTO "decisions" VALUES(10,'ADR-10: Konfigurierbare Warnschwellwerte','Schwellwerte fuer Warnhinweise sind pro Kind konfigurierbar (aktivieren + Werte setzen). Defaults: <5 nasse Windeln/24h, kein Stuhl >48h, Trinkmenge konfigurierbar.','Jedes Kind hat unterschiedliche Normalwerte. User muss Warnungen an- und abschalten koennen.','["Feste Schwellwerte", "Nur globale Defaults"]','active','2026-04-20 04:54:50');
